#include<bits/stdc++.h>
#define ll long long
using namespace std;
const int MOD=20123,MAXN=1e4+5,MAXM=1e2+10;
int n,m,f[MAXN][MAXM]={0},x[MAXN][MAXM],y;ll ans=0,k;
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	scanf("%d%d",&n,&m);
	for(int i=1;i<=n;++i){
		for(int j=0;j<m;++j){
			scanf("%d%d",&f[i][j],&x[i][j]),f[i][m]+=(f[i][j]==1);
		}
	}scanf("%d",&y);
	for(int i=1;i<=n;++i){
		ans=(ans+x[i][y])%MOD,k=0;int j=y;
		for(;;j=((j+1==m)?(0):(j+1))){k+=(f[i][j]==1);if(k==(x[i][y]-1)%f[i][m]+1)break;}y=j;
	}printf("%lld",ans%MOD);
	return false;
}
